/* ──────────────────────────────────────────────────────────────
   CANVAS BACKGROUND (gradient gold, stripe texture, vignette)
   Runs immediately before DOMContentLoaded — prevents white flash
   ────────────────────────────────────────────────────────────── */
(function () {
    var canvas = document.getElementById('bg-canvas');
    if (!canvas) return;
    var ctx = canvas.getContext('2d');

    function drawBackground() {
        var W   = window.innerWidth;
        var H   = window.innerHeight;
        var dpr = window.devicePixelRatio || 1;

        canvas.width  = Math.round(W * dpr);
        canvas.height = Math.round(H * dpr);
        canvas.style.width  = W + 'px';
        canvas.style.height = H + 'px';
        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

        var isMobile = W < 640;

        var g = ctx.createLinearGradient(0, 0, W, 0);
        if (isMobile) {
            g.addColorStop(0,    '#b8935a');
            g.addColorStop(0.25, '#f5e8b0');
            g.addColorStop(0.50, '#b89550');
            g.addColorStop(0.75, '#f5e8b0');
            g.addColorStop(1,    '#b8935a');
        } else {
            g.addColorStop(0,    '#b8935a');
            g.addColorStop(0.30, '#f5e8b0');
            g.addColorStop(0.65, '#c9a868');
            g.addColorStop(0.80, '#ecd898');
            g.addColorStop(0.85, '#d0b070');
            g.addColorStop(1,    '#d0b070');
        }
        ctx.fillStyle = g;
        ctx.fillRect(0, 0, W, H);

        for (var y = 0; y <= H; y += 12) {
            ctx.fillStyle = 'rgba(255,255,255,0.40)';
            ctx.fillRect(0, y, W, 1);
            ctx.fillStyle = 'rgba(0,0,0,0.15)';
            ctx.fillRect(0, y + 5, W, 1);
        }

        if (!isMobile) {
            var vL = ctx.createLinearGradient(0, 0, W * 0.15, 0);
            vL.addColorStop(0, 'rgba(0,0,0,0.10)');
            vL.addColorStop(1, 'rgba(0,0,0,0)');
            ctx.fillStyle = vL;
            ctx.fillRect(0, 0, W, H);

            var vR = ctx.createLinearGradient(W * 0.85, 0, W, 0);
            vR.addColorStop(0, 'rgba(0,0,0,0)');
            vR.addColorStop(1, 'rgba(0,0,0,0.10)');
            ctx.fillStyle = vR;
            ctx.fillRect(0, 0, W, H);
        }
    }

    drawBackground();

    var resizeTimer;
    window.addEventListener('resize', function () {
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(drawBackground, 150);
    });
    window.addEventListener('orientationchange', function () {
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(drawBackground, 300);
    });
})();

/* ──────────────────────────────────────────────────────────────
   PULL-TO-REFRESH (mobile, non-iOS only)
   ────────────────────────────────────────────────────────────── */
(function () {
    var isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent);
    if (isIOS) return;
    if (window.innerWidth >= 640) return;

    var indicator = document.getElementById('ptr-indicator');
    var spinner   = document.getElementById('ptr-spinner');
    var startY = 0, pulling = false, triggered = false;
    var THRESHOLD = 80, MAX_HEIGHT = 60;

    document.addEventListener('touchstart', function (e) {
        if (e.target.closest('.scratch-wrap')) { pulling = false; return; }
        if (window.scrollY === 0 || document.documentElement.scrollTop === 0) {
            startY = e.touches[0].clientY;
            pulling = true;
            triggered = false;
        }
    }, { passive: true });

    document.addEventListener('touchmove', function (e) {
        if (!pulling) return;
        var deltaY = e.touches[0].clientY - startY;
        if (deltaY <= 0) { pulling = false; return; }
        var progress = Math.min(deltaY / THRESHOLD, 1);
        var height   = Math.min(deltaY * 0.5, MAX_HEIGHT);
        indicator.style.height  = height + 'px';
        spinner.style.opacity   = progress;
        spinner.style.transform = 'rotate(' + (progress * 180) + 'deg)';
        if (deltaY >= THRESHOLD && !triggered) {
            triggered = true;
            spinner.classList.add('spinning');
        }
    }, { passive: true });

    document.addEventListener('touchend', function () {
        if (!pulling) return;
        pulling = false;
        if (triggered) {
            indicator.style.height = MAX_HEIGHT + 'px';
            setTimeout(function () { window.location.reload(); }, 400);
        } else {
            indicator.style.height  = '0';
            spinner.style.opacity   = '0';
            spinner.classList.remove('spinning');
        }
    }, { passive: true });
})();

/* ──────────────────────────────────────────────────────────────
   CANVAS GOLD GRADIENT BACKGROUNDS (force-dark fix)
   ────────────────────────────────────────────────────────────── */
(function () {
    function drawGoldGradient(canvas, stops, borderRadius) {
        if (!canvas) return;
        var parent = canvas.parentElement;
        if (!parent) return;
        var dpr = window.devicePixelRatio || 1;
        var W   = parent.offsetWidth;
        var H   = parent.offsetHeight;
        if (W === 0 || H === 0) return;

        canvas.width  = Math.round(W * dpr);
        canvas.height = Math.round(H * dpr);
        canvas.style.width  = W + 'px';
        canvas.style.height = H + 'px';

        var ctx = canvas.getContext('2d');
        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

        if (borderRadius) {
            ctx.beginPath();
            var r = borderRadius;
            ctx.moveTo(r, 0);
            ctx.lineTo(W - r, 0); ctx.quadraticCurveTo(W, 0, W, r);
            ctx.lineTo(W, H - r); ctx.quadraticCurveTo(W, H, W - r, H);
            ctx.lineTo(r, H);     ctx.quadraticCurveTo(0, H, 0, H - r);
            ctx.lineTo(0, r);     ctx.quadraticCurveTo(0, 0, r, 0);
            ctx.closePath();
            ctx.clip();
        }

        var g = ctx.createLinearGradient(0, 0, W, 0);
        stops.forEach(function (s) { g.addColorStop(s[0], s[1]); });
        ctx.fillStyle = g;
        ctx.fillRect(0, 0, W, H);
    }

    var STOPS_DESKTOP_LOGO = [
        [0, '#b29560'], [0.30, '#c2a571'], [0.50, '#ecd898'], [0.80, '#ecd898'], [1, '#e2cf96']
    ];
    var STOPS_MOBILE_LOGO = [
        [0, '#e2cd96'], [0.20, '#f5e8b0'], [0.50, '#ba9653'], [0.80, '#ecd898'], [1, '#e2cf96']
    ];
    var STOPS_SCRATCH_WRAP = [
        [0, '#d7bd80'], [0.30, '#c8aa6c'], [0.60, '#d8c386'], [0.80, '#bda066'], [1, '#bda066']
    ];
    var STOPS_LINIER_MOBILE = [
        [0, '#cfb27a'], [0.20, '#f5e8b0'], [0.50, '#ba9653'], [0.80, '#f5e8b0'], [1, '#cfb27a']
    ];

    var CANVAS_CONFIG = {
        'canvas-bg-desktop-logo':  [STOPS_DESKTOP_LOGO,  0],
        'canvas-bg-scratch-wrap':  [STOPS_SCRATCH_WRAP,  7],
        'canvas-bg-mobile-logo':   [STOPS_MOBILE_LOGO,   0],
        'canvas-bg-linier-mobile': [STOPS_LINIER_MOBILE, 7],
    };

    function renderCanvas(id) {
        var cfg = CANVAS_CONFIG[id];
        if (!cfg) return;
        drawGoldGradient(document.getElementById(id), cfg[0], cfg[1]);
    }

    function renderAll() { Object.keys(CANVAS_CONFIG).forEach(renderCanvas); }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', renderAll);
    } else {
        renderAll();
    }

    var resizeTimer;
    window.addEventListener('resize', function () {
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(renderAll, 150);
    });
    window.addEventListener('orientationchange', function () {
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(renderAll, 300);
    });

    if (typeof ResizeObserver !== 'undefined') {
        document.addEventListener('DOMContentLoaded', function () {
            Object.keys(CANVAS_CONFIG).forEach(function (id) {
                var canvas = document.getElementById(id);
                if (!canvas || !canvas.parentElement) return;
                var cfg = CANVAS_CONFIG[id];
                var ro = new ResizeObserver(function () {
                    drawGoldGradient(canvas, cfg[0], cfg[1]);
                });
                ro.observe(canvas.parentElement);
            });
        });
    }

    window.ggRenderCanvasBg = renderAll;

    /* Shine canvas */
    function renderShineCanvases() {
        document.querySelectorAll('.scratch-shine > canvas.shine-canvas').forEach(function (canvas) {
            var parent = canvas.parentElement;
            if (!parent) return;
            var dpr = window.devicePixelRatio || 1;
            var W = parent.offsetWidth || 1;
            var H = parent.offsetHeight || 1;

            canvas.width  = Math.round(W * dpr);
            canvas.height = Math.round(H * dpr);
            canvas.style.width  = W + 'px';
            canvas.style.height = H + 'px';

            var ctx = canvas.getContext('2d');
            ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
            var g = ctx.createLinearGradient(0, 0, W, 0);
            g.addColorStop(0,    'rgba(255,255,255,0)');
            g.addColorStop(0.30, 'rgba(255,255,255,0.08)');
            g.addColorStop(0.50, 'rgba(255,255,255,0.55)');
            g.addColorStop(0.70, 'rgba(255,255,255,0.08)');
            g.addColorStop(1,    'rgba(255,255,255,0)');
            ctx.fillStyle = g;
            ctx.fillRect(0, 0, W, H);
        });
    }

    document.addEventListener('DOMContentLoaded', renderShineCanvases);
    window.ggRenderShine = renderShineCanvases;
})();

/* ──────────────────────────────────────────────────────────────
   CANVAS IMAGE ASSETS: Logo & Rivets (force-dark fix)
   ────────────────────────────────────────────────────────────── */
(function () {
    var LOGO_SRC  = 'data:image/png;base64,';
    var RIVET_SRC = 'data:image/png;base64,';

    function drawImageToCanvas(canvas, img) {
        if (!canvas || !img) return;
        var dpr = window.devicePixelRatio || 1;
        var W = canvas.offsetWidth  || img.naturalWidth;
        var H = canvas.offsetHeight || img.naturalHeight;
        if (W === 0) W = img.naturalWidth;
        if (H === 0) H = img.naturalHeight;

        canvas.width  = Math.round(W * dpr);
        canvas.height = Math.round(H * dpr);
        canvas.style.width  = W + 'px';
        canvas.style.height = H + 'px';

        var ctx = canvas.getContext('2d');
        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
        ctx.clearRect(0, 0, W, H);
        ctx.drawImage(img, 0, 0, W, H);
    }

    function renderLogo(img) {
        ['canvas-logo-desktop', 'gg-logo-mobile'].forEach(function (id) {
            var canvas = document.getElementById(id);
            if (!canvas) return;
            requestAnimationFrame(function () {
                var W = canvas.offsetWidth;
                if (W === 0) {
                    var parent = canvas.parentElement;
                    W = parent ? parent.offsetWidth - 16 : img.naturalWidth;
                }
                var H = Math.round(W * (img.naturalHeight / img.naturalWidth));
                canvas.style.width  = W + 'px';
                canvas.style.height = H + 'px';
                drawImageToCanvas(canvas, img);
            });
        });
    }

    function renderRivets(img) {
        document.querySelectorAll('canvas.rivet-canvas').forEach(function (canvas) {
            var size = canvas.offsetWidth || 19;
            canvas.style.width  = size + 'px';
            canvas.style.height = size + 'px';
            drawImageToCanvas(canvas, img);
        });
    }

    var logoImg  = new Image();
    var rivetImg = new Image();
    var loaded   = 0;

    function onLoad() {
        loaded++;
        if (loaded >= 2) renderAll();
    }

    function renderAll() {
        renderLogo(logoImg);
        renderRivets(rivetImg);
    }

    logoImg.onload  = onLoad;
    rivetImg.onload = onLoad;
    logoImg.src     = LOGO_SRC;
    rivetImg.src    = RIVET_SRC;

    var resizeTimer;
    window.addEventListener('resize', function () {
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(renderAll, 150);
    });

    window.ggRenderImageAssets = renderAll;
})();

/* ──────────────────────────────────────────────────────────────
   CANVAS TEXT: Tagline "GOSOK DAN TEMUKAN" (force-dark fix)
   ────────────────────────────────────────────────────────────── */
(function () {
    var TEXT       = 'GOSOK DAN TEMUKAN';
    var COLOR      = '#760000';
    var FONT_STYLE = '900 italic';

    function drawTaglineCanvas(canvas, fontSize) {
        if (!canvas) return;
        var dpr = window.devicePixelRatio || 1;
        var tmpCtx = document.createElement('canvas').getContext('2d');
        tmpCtx.font = FONT_STYLE + ' ' + fontSize + 'px "Source Sans 3", sans-serif';
        var textW = tmpCtx.measureText(TEXT).width;
        var textH = fontSize * 1.2;
        var W = Math.ceil(textW) + 4;
        var H = Math.ceil(textH);

        canvas.width  = Math.round(W * dpr);
        canvas.height = Math.round(H * dpr);
        canvas.style.width  = W + 'px';
        canvas.style.height = H + 'px';

        var ctx = canvas.getContext('2d');
        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
        ctx.clearRect(0, 0, W, H);
        ctx.font         = FONT_STYLE + ' ' + fontSize + 'px "Source Sans 3", sans-serif';
        ctx.fillStyle    = COLOR;
        ctx.textBaseline = 'top';
        ctx.textAlign    = 'center';
        ctx.fillText(TEXT, W / 2, (H - fontSize) / 2);
    }

    function getFontSize(canvasId) {
        var vw = window.innerWidth;
        var vh = window.innerHeight;

        if (canvasId === 'canvas-tagline-desktop') {
            if (vw >= 1500 && vw <= 1599 && vh >= 730) return Math.round(vw * 0.035);
            if (vw >= 1400 && vw <= 1599 && vh >= 750) return Math.round(vw * 0.035);
            if (vw >= 1650 && vw <= 1799 && vh >= 900) return Math.round(Math.min(Math.max(vw * 0.036, 25.6), 60.8));
            if (vw >= 1800 && vh >= 900)               return Math.round(Math.min(Math.max(vw * 0.036, 25.6), 64));
            return Math.round(Math.min(Math.max(vw * 0.036, 25.6), 44.8));
        } else {
            return Math.round(Math.min(Math.max(vw * 0.07, 24), 42));
        }
    }

    function renderTaglines() {
        var isIOS   = /iPad|iPhone|iPod/.test(navigator.userAgent);
        var desktop = document.getElementById('canvas-tagline-desktop');
        var mobile  = document.getElementById('canvas-tagline-mobile');
        if (desktop) drawTaglineCanvas(desktop, getFontSize('canvas-tagline-desktop'));
        if (mobile) {
            drawTaglineCanvas(mobile, getFontSize('canvas-tagline-mobile'));
            mobile.style.marginTop = isIOS ? '0px' : '4px';
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', renderTaglines);
    } else {
        renderTaglines();
    }

    if (document.fonts && document.fonts.ready) {
        document.fonts.ready.then(renderTaglines);
    }

    var resizeTimer;
    window.addEventListener('resize', function () {
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(renderTaglines, 150);
    });

    window.ggRenderTaglines = renderTaglines;
})();

/* ──────────────────────────────────────────────────────────────
   CANVAS TEXT: Scratch-reveal & tagline-reveal-slot (force-dark fix)
   ────────────────────────────────────────────────────────────── */
(function () {
    var COLOR = '#760000';
    var FONT  = '"Source Sans 3", sans-serif';

    function drawRevealText(canvas, basePx, padTop, padBottom) {
        if (!canvas) return;
        var dpr = window.devicePixelRatio || 1;
        padTop    = padTop    || 0;
        padBottom = padBottom || 0;

        var line1 = 'TARIKAN & TAMPILAN';
        var line2 = 'LEBIH BAIK';
        var size1 = basePx;
        var size2 = Math.round(basePx * 1.85);
        var lineGap = Math.round(basePx * 0.05);

        var tmp = document.createElement('canvas').getContext('2d');
        var measureScale = Math.min(dpr, 2);

        tmp.font = '800 italic ' + (size1 * measureScale) + 'px ' + FONT;
        var m1 = tmp.measureText(line1);
        var w1 = m1.width / measureScale;
        var h1 = ((m1.actualBoundingBoxAscent || size1 * 0.8) + (m1.actualBoundingBoxDescent || size1 * 0.2)) / measureScale;

        tmp.font = '800 italic ' + (size2 * measureScale) + 'px ' + FONT;
        var m2 = tmp.measureText(line2);
        var w2 = m2.width / measureScale;
        var h2 = ((m2.actualBoundingBoxAscent || size2 * 0.8) + (m2.actualBoundingBoxDescent || size2 * 0.2)) / measureScale;

        var W = Math.ceil(Math.max(w1, w2) * 1.08) + 16;
        var H = Math.ceil(padTop + h1 + lineGap + h2 + padBottom);

        canvas.width  = Math.round(W * dpr);
        canvas.height = Math.round(H * dpr);
        canvas.style.width  = W + 'px';
        canvas.style.height = H + 'px';

        var ctx = canvas.getContext('2d');
        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
        ctx.clearRect(0, 0, W, H);
        ctx.textAlign    = 'center';
        ctx.textBaseline = 'top';
        ctx.fillStyle    = COLOR;

        ctx.font = '800 italic ' + size1 + 'px ' + FONT;
        ctx.fillText(line1, W / 2, padTop);

        ctx.font = '800 italic ' + size2 + 'px ' + FONT;
        ctx.fillText(line2, W / 2, padTop + h1 + lineGap);
    }

    function getRevealBasePx(isMobile, forSlot) {
        var vw = window.innerWidth;
        var vh = window.innerHeight;
        var scale = (forSlot && !isMobile) ? 0.85 : 1;

        if (isMobile) {
            if (vw <= 370 && vw >= 350 && vh <= 600) return Math.round(Math.min(Math.max(vw * 0.06, 19), 30));
            return Math.round(Math.min(Math.max(vw * 0.0674, 19), 30));
        } else {
            var px;
            if      (vw >= 1500 && vw <= 1599 && vh >= 730) px = Math.round(vw * 0.0334);
            else if (vw >= 1400 && vw <= 1599 && vh >= 750) px = Math.round(vw * 0.0334);
            else if (vw >= 1650 && vw <= 1799 && vh >= 900) px = Math.round(Math.min(Math.max(vw * 0.036, 22), 60));
            else if (vw >= 1800 && vh >= 900)               px = Math.round(vw * 0.0334);
            else                                             px = Math.round(Math.min(Math.max(vw * 0.035, 22), 44));
            return Math.round(px * scale);
        }
    }

    function centerCanvasInWrap(canvas, wrap, padBottom) {
        var wrapH   = wrap.offsetHeight;
        var canvasH = parseFloat(canvas.style.height) || 0;
        var visualH = canvasH - (padBottom || 0);
        if (wrapH > 0 && visualH > 0) {
            var topPx = Math.round((wrapH - visualH) / 2);
            var isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent);
            if (isIOS) topPx = Math.max(0, topPx - 12);
            canvas.style.top       = topPx + 'px';
            canvas.style.left      = '50%';
            canvas.style.transform = 'translateX(-50%)';
        }
    }

    function renderRevealCanvases() {
        var wrapDesktop = document.getElementById('sc-desktop');
        if (wrapDesktop) {
            var scratchWrap = wrapDesktop.closest('.scratch-wrap');
            var rc = scratchWrap.querySelector('.scratch-reveal-canvas');
            if (rc) {
                drawRevealText(rc, getRevealBasePx(false), 0, 0);
                centerCanvasInWrap(rc, scratchWrap, 0);
            }
        }
        var wrapMobile = document.getElementById('sc-mobile');
        if (wrapMobile) {
            var scratchWrap = wrapMobile.closest('.scratch-wrap');
            var rc = scratchWrap.querySelector('.scratch-reveal-canvas');
            if (rc) {
                var isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent);
                var padBtm = isIOS ? 20 : 3;
                drawRevealText(rc, getRevealBasePx(true), 0, padBtm);
                centerCanvasInWrap(rc, scratchWrap, padBtm);
            }
        }
    }

    window.ggDrawRevealSlot = function (slotEl, isMobile) {
        if (!slotEl) return;
        slotEl.innerHTML = '';

        var canvas = document.createElement('canvas');
        var isIOS  = /iPad|iPhone|iPod/.test(navigator.userAgent);
        canvas.style.display   = 'block';
        canvas.style.marginTop = isMobile ? (isIOS ? '-16px' : '0px') : '0';
        canvas.style.margin    = '0 auto';
        slotEl.appendChild(canvas);

        var basePx    = getRevealBasePx(isMobile, true);
        var padTop    = (!isMobile) ? 6 : 0;
        var padBottom = (!isMobile) ? 0 : (isIOS ? 20 : 3);
        drawRevealText(canvas, basePx, padTop, padBottom);

        var origAnchor = isMobile
            ? document.querySelector('#sc-mobile').closest('.scratch-wrap').querySelector('.scratch-reveal-anchor')
            : document.querySelector('#sc-desktop').closest('.scratch-wrap').querySelector('.scratch-reveal-anchor');

        if (origAnchor) {
            var a = document.createElement('a');
            /* ── DV360 CLICK MACRO ── */
            a.href = origAnchor.getAttribute('href') || '#';
            a.target = '_blank';
            a.style.cssText = 'position:absolute;inset:0;display:block;';

            var wrapper = document.createElement('div');
            var mtop    = (isMobile && !isIOS) ? '0.5rem' : '0';
            wrapper.style.cssText = 'position:relative;display:inline-block;line-height:0;font-size:0;margin:0 auto;margin-top:' + mtop + ';';
            slotEl.style.textAlign = 'center';
            slotEl.innerHTML = '';
            wrapper.appendChild(canvas);
            wrapper.appendChild(a);
            slotEl.appendChild(wrapper);
        }
    };

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', function () {
            renderRevealCanvases();
            if (document.fonts && document.fonts.ready) {
                document.fonts.ready.then(renderRevealCanvases);
            }
        });
    } else {
        renderRevealCanvases();
        if (document.fonts && document.fonts.ready) {
            document.fonts.ready.then(renderRevealCanvases);
        }
    }

    var resizeTimer;
    window.addEventListener('resize', function () {
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(renderRevealCanvases, 150);
    });

    window.ggRenderRevealCanvases = renderRevealCanvases;
})();

/* ──────────────────────────────────────────────────────────────
   OVERFLOW FIX (mobile)
   ────────────────────────────────────────────────────────────── */
(function () {
    if (window.innerWidth < 640) {
        var main     = document.querySelector('main');
        var ggMobile = document.getElementById('gg-mobile');
        var ggBanner = document.getElementById('gg-banner');
        if (main)     main.style.overflow     = 'visible';
        if (ggMobile) ggMobile.style.overflow = 'visible';
        if (ggBanner) ggBanner.style.overflow = 'visible';
    }
})();

/* ──────────────────────────────────────────────────────────────
   SCRATCH CARD ENGINE
   ────────────────────────────────────────────────────────────── */
(function () {
    'use strict';

    /* ── DV360 CLICK MACRO helper ── */
    function dv360Href(originalHref) {
        return '%%CLICK_URL_UNESC%%' + (originalHref || '#');
    }

    function initScratch(canvasId) {
        var canvas = document.getElementById(canvasId);
        if (!canvas) return;

        var wrap = canvas.closest('.scratch-wrap');
        var ctx  = canvas.getContext('2d', { willReadFrequently: true });
        var W, H;
        var drawing = false;

        var improvedImg = new Image();
        improvedImg.src = 'data:image/png;base64,';

        function resize() {
            var dpr = window.devicePixelRatio || 1;
            W = wrap.offsetWidth;
            H = wrap.offsetHeight;
            canvas.width  = W * dpr;
            canvas.height = H * dpr;
            canvas.style.width  = W + 'px';
            canvas.style.height = H + 'px';
            ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
            drawCover();
        }

        function drawCover() {
            var g = ctx.createLinearGradient(0, 0, W, H);
            g.addColorStop(0,   '#920000');
            g.addColorStop(0.4, '#760000');
            ctx.fillStyle = g;
            ctx.fillRect(0, 0, W, H);

            function drawImprovedImg() {
                var imgW = W * 0.78;
                var imgH = imgW * (improvedImg.naturalHeight / improvedImg.naturalWidth);
                var imgX = (W - imgW) / 2;
                var imgY = (H - imgH) / 2 + (H * 0.02);
                ctx.drawImage(improvedImg, imgX, imgY, imgW, imgH);
            }
            if (improvedImg.complete && improvedImg.naturalWidth > 0) {
                drawImprovedImg();
            } else {
                improvedImg.onload = function () { drawImprovedImg(); };
            }
        }

        var lastX = null, lastY = null;

        function scratchAt(cx, cy) {
            ctx.globalCompositeOperation = 'destination-out';
            var brushWidth = Math.max(88, W * 0.28);
            var bristles   = 18;

            for (var i = 0; i < bristles; i++) {
                var t        = i / (bristles - 1);
                var offset   = (t - 0.5) * brushWidth;
                var jitterX  = (Math.random() - 0.5) * 10;
                var jitterY  = (Math.random() - 0.5) * 4;
                var alpha    = 0.4 + Math.random() * 0.55;
                var width    = 4 + Math.random() * 10;
                var edgeFade = 1 - Math.pow(Math.abs(t - 0.5) * 2, 1.5);
                alpha *= edgeFade;
                if (alpha < 0.05) continue;

                ctx.beginPath();
                ctx.lineWidth   = width;
                ctx.lineCap     = 'round';
                ctx.strokeStyle = 'rgba(0,0,0,' + alpha + ')';

                if (lastX !== null) {
                    var midX = (lastX + cx) / 2 + jitterX;
                    var midY = (lastY + cy) / 2 + jitterY;
                    ctx.moveTo(lastX + offset, lastY + offset * 0.15);
                    ctx.quadraticCurveTo(
                        midX + offset, midY + offset * 0.15,
                        cx + offset + jitterX * 0.5,
                        cy + offset * 0.15 + jitterY * 0.5
                    );
                } else {
                    ctx.arc(
                        cx + offset + jitterX * 0.5,
                        cy + offset * 0.15 + jitterY * 0.5,
                        width / 2, 0, Math.PI * 2
                    );
                }
                ctx.stroke();
            }

            ctx.globalCompositeOperation = 'source-over';
            lastX = cx;
            lastY = cy;
            checkRevealed();
        }

        function checkRevealed() {
            if (wrap.classList.contains('text-revealed')) return;

            var sample      = ctx.getImageData(0, 0, canvas.width, canvas.height);
            var pixels      = sample.data;
            var total       = pixels.length / 4;
            var transparent = 0;
            for (var i = 3; i < pixels.length; i += 4) {
                if (pixels[i] < 128) transparent++;
            }

            if (transparent / total >= 0.999) {
                wrap.classList.add('text-revealed');

                canvas.style.pointerEvents = 'none';
                canvas.style.cursor        = 'default';
                wrap.querySelectorAll('.scratch-reveal a').forEach(function (a) {
                    a.style.pointerEvents = 'none';
                    a.style.cursor        = 'default';
                });
                var revealDiv = wrap.querySelector('.scratch-reveal');
                if (revealDiv) revealDiv.style.pointerEvents = 'none';

                canvas.removeEventListener('mousedown',  handleMouseDown);
                canvas.removeEventListener('mousemove',  handleMouseMove);
                canvas.removeEventListener('mouseup',    handleMouseUp);
                canvas.removeEventListener('mouseleave', handleMouseUp);
                canvas.removeEventListener('touchstart', handleTouchStart, { passive: false });
                canvas.removeEventListener('touchmove',  handleTouchMove,  { passive: false });
                canvas.removeEventListener('touchend',   handleTouchEnd);
                document.removeEventListener('mousemove', handleDocMouseMove);
                document.removeEventListener('mouseup',   handleDocMouseUp);
                drawing = false;
                lastX = null;
                lastY = null;

                var isDesktop = (canvasId === 'sc-desktop');
                var slotId    = isDesktop ? 'tagline-slot-desktop' : 'tagline-slot-mobile';

                document.querySelectorAll('.tagline').forEach(function (t) {
                    t.classList.remove('do-zoom-pulse', 'do-zoom-pulse-mobile');
                    t.style.animation = 'none';
                });

                /* Step 1: hide tagline */
                document.querySelectorAll('.tagline').forEach(function (t) {
                    t.classList.add('tagline-hidden');
                });
                setTimeout(function () {
                    document.querySelectorAll('.tagline').forEach(function (t) {
                        t.classList.add('tagline-gone');
                    });
                }, 400);

                /* Step 2: redraw cover */
                setTimeout(function () {
                    canvas.style.transition = 'none';
                    canvas.style.opacity    = '0';
                    ctx.globalCompositeOperation = 'source-over';
                    ctx.clearRect(0, 0, W, H);
                    drawCover();

                    requestAnimationFrame(function () {
                        requestAnimationFrame(function () {
                            canvas.style.transition = 'opacity 0.5s ease-in';
                            canvas.style.opacity    = '1';
                        });
                    });

                    /* Step 3: zoom + shake */
                    setTimeout(function () {
                        wrap.classList.remove('reveal-zoom');
                        void wrap.offsetWidth;
                        requestAnimationFrame(function () {
                            wrap.classList.add('reveal-zoom');
                            setTimeout(function () { wrap.classList.remove('reveal-zoom'); }, 1200);
                        });

                        document.body.classList.add('screen-shake-2');
                        document.body.addEventListener('animationend', function cleanup2(e) {
                            if (e.animationName === 'screenShake2') {
                                document.body.classList.remove('screen-shake-2');
                                document.body.removeEventListener('animationend', cleanup2);
                            }
                        });

                        /* Step 4: show anchor in slot */
                        var slot = document.getElementById(slotId);
                        if (slot) {
                            if (typeof window.ggDrawRevealSlot === 'function') {
                                window.ggDrawRevealSlot(slot, !isDesktop);
                            }
                            slot.classList.add('do-appear');

                            if (typeof window.ggRenderCanvasBg === 'function') {
                                requestAnimationFrame(function () {
                                    window.ggRenderCanvasBg();
                                    setTimeout(window.ggRenderCanvasBg, 1050);
                                });
                            }

                            /* Step 5: redirect sequence */
                            setTimeout(function () {
                                document.dispatchEvent(new CustomEvent('gg:price-bg-reveal', { detail: { isMobile: !isDesktop } }));

                                setTimeout(function () {
                                    document.dispatchEvent(new CustomEvent('gg:price-text-reveal', { detail: { isMobile: !isDesktop } }));

                                    setTimeout(function () {
                                        window.location.href = window.clickTag;
                                    }, 1800);
                                }, 1500);
                            }, 0);
                        }
                    }, 600);
                }, 300);
            }
        }

        function coords(e) {
            var r   = canvas.getBoundingClientRect();
            var src = e.touches ? e.touches[0] : e;
            return {
                x: (src.clientX - r.left) * (W / r.width),
                y: (src.clientY - r.top)  * (H / r.height)
            };
        }

        function isTransparent(x, y) {
            var pixel = ctx.getImageData(x, y, 1, 1).data;
            return pixel[3] < 128;
        }

        function handleMouseDown(e) {
            if (wrap.classList.contains('text-revealed')) return;
            drawing = true;
            var p = coords(e);
            if (!isTransparent(p.x, p.y)) scratchAt(p.x, p.y);
            document.addEventListener('mousemove', handleDocMouseMove);
            document.addEventListener('mouseup',   handleDocMouseUp);
        }

        function handleDocMouseMove(e) {
            if (!drawing) return;
            var r = canvas.getBoundingClientRect();
            var x = (e.clientX - r.left) * (W / r.width);
            var y = (e.clientY - r.top)  * (H / r.height);
            if (x >= 0 && x <= W && y >= 0 && y <= H) {
                scratchAt(x, y);
            } else {
                lastX = null;
                lastY = null;
            }
        }

        function handleDocMouseUp() {
            drawing = false;
            lastX   = null;
            lastY   = null;
            document.removeEventListener('mousemove', handleDocMouseMove);
            document.removeEventListener('mouseup',   handleDocMouseUp);
        }

        function handleMouseMove(e) {
            if (drawing) return;
            if (wrap.classList.contains('text-revealed')) {
                canvas.style.pointerEvents = 'none';
                return;
            }
            canvas.style.pointerEvents = 'auto';
            canvas.style.cursor        = 'crosshair';
        }

        function handleMouseUp() { /* handled by handleDocMouseUp */ }

        function handleTouchStart(e) {
            if (wrap.classList.contains('text-revealed')) return;
            var p = coords(e);
            if (isTransparent(p.x, p.y)) {
                e.preventDefault();
                drawing = true;
                lastX = null;
                lastY = null;
                return;
            }
            e.preventDefault();
            drawing = true;
            scratchAt(p.x, p.y);
        }

        function handleTouchMove(e) {
            if (!drawing) return;
            e.preventDefault();
            var p = coords(e);
            scratchAt(p.x, p.y);
        }

        function handleTouchEnd() {
            drawing = false;
            lastX   = null;
            lastY   = null;
        }

        canvas.addEventListener('mousedown',  handleMouseDown);
        canvas.addEventListener('mousemove',  handleMouseMove);
        canvas.addEventListener('mouseup',    handleMouseUp);
        canvas.addEventListener('mouseleave', handleMouseUp);
        canvas.addEventListener('touchstart', handleTouchStart, { passive: false });
        canvas.addEventListener('touchmove',  handleTouchMove,  { passive: false });
        canvas.addEventListener('touchend',   handleTouchEnd);

        resize();
        var resizeTimer;
        window.addEventListener('resize', function () {
            clearTimeout(resizeTimer);
            resizeTimer = setTimeout(resize, 150);
        });
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', function () {
            initScratch('sc-desktop');
            initScratch('sc-mobile');
        });
    } else {
        initScratch('sc-desktop');
        initScratch('sc-mobile');
    }
})();

/* ──────────────────────────────────────────────────────────────
   AOS INIT + PAGE-SHOW + SCREEN SHAKE + ZOOM LOOP + SHINE
   ────────────────────────────────────────────────────────────── */
document.addEventListener('DOMContentLoaded', function () {
    AOS.init({ once: true, startEvent: 'DOMContentLoaded', offset: 0 });

    /* Reload on bfcache restore (after Back navigation) */
    window.addEventListener('pageshow', function (e) {
        if (e.persisted) window.location.reload();
    });

    /* Screen shake #1 */
    (function () {
        var shakeTriggered = false;
        function triggerScreenShake() {
            if (shakeTriggered) return;
            shakeTriggered = true;
            document.body.classList.add('screen-shake');
            document.body.addEventListener('animationend', function cleanup(e) {
                if (e.animationName === 'screenShake') {
                    document.body.classList.remove('screen-shake');
                    document.body.removeEventListener('animationend', cleanup);
                }
            });
        }
        setTimeout(triggerScreenShake, 1800);
    })();

    /* Zoom alternating loop */
    (function () {
        var ZOOM_DURATION  = 900;
        var ZOOM_GAP       = 200;
        var STEP_INTERVAL  = ZOOM_DURATION + ZOOM_GAP;

        function getTaglines() {
            return document.querySelectorAll('.tagline:not(.tagline-hidden)');
        }

        function zoomTagline() {
            var isMobile = window.innerWidth < 640;
            getTaglines().forEach(function (el) {
                el.classList.remove('do-zoom-pulse', 'do-zoom-pulse-mobile');
                void el.offsetWidth;
                el.classList.add(isMobile ? 'do-zoom-pulse-mobile' : 'do-zoom-pulse');
            });
        }

        function startLoop() {
            zoomTagline();
            var step = 1;
            setInterval(function () {
                if (!document.querySelector('.tagline:not(.tagline-hidden)')) return;
                if (step % 2 === 0) zoomTagline();
                step++;
            }, STEP_INTERVAL);
        }

        var loopStarted = false;
        function startLoopOnce() {
            if (loopStarted) return;
            loopStarted = true;
            startLoop();
        }

        if (window.innerWidth >= 640) {
            document.querySelectorAll('.scratch-shine').forEach(function (shineEl) {
                shineEl.addEventListener('animationend', function onShineDone(e) {
                    if (e.animationName === 'scratchShine') {
                        shineEl.removeEventListener('animationend', onShineDone);
                        setTimeout(function () {
                            document.querySelectorAll('.scratch-shine').forEach(function (el) {
                                var wrap = el.closest('.scratch-wrap');
                                if (wrap) {
                                    wrap.classList.remove('reveal-zoom');
                                    void wrap.offsetWidth;
                                    requestAnimationFrame(function () {
                                        wrap.classList.add('reveal-zoom');
                                        setTimeout(function () { wrap.classList.remove('reveal-zoom'); }, 1200);
                                    });
                                }
                            });
                        }, 0);
                        setTimeout(startLoopOnce, 1500);
                    }
                });
            });
            setTimeout(startLoopOnce, 9000);
        } else {
            setTimeout(startLoopOnce, 6500);
        }
    })();

    /* Shine effect */
    (function () {
        var shineTriggered = false;
        function triggerShine() {
            if (shineTriggered) return;
            shineTriggered = true;
            document.querySelectorAll('.scratch-shine').forEach(function (el) {
                el.classList.add('do-shine');
            });

            if (window.innerWidth < 640) {
                setTimeout(function () {
                    document.querySelectorAll('.scratch-shine').forEach(function (el) {
                        var wrap = el.closest('.scratch-wrap');
                        if (wrap) {
                            wrap.classList.remove('reveal-zoom');
                            void wrap.offsetWidth;
                            requestAnimationFrame(function () {
                                wrap.classList.add('reveal-zoom');
                                setTimeout(function () { wrap.classList.remove('reveal-zoom'); }, 1200);
                            });
                        }
                    });
                }, 1000);
            }
        }

        if (window.innerWidth >= 640) {
            setTimeout(triggerShine, 4000);
        } else {
            var logoMobile     = document.getElementById('gg-logo-mobile');
            var shineFiredByAos = false;
            if (logoMobile) {
                logoMobile.addEventListener('aos:in', function onLogoDone() {
                    logoMobile.removeEventListener('aos:in', onLogoDone);
                    shineFiredByAos = true;
                    setTimeout(triggerShine, 1500);
                });
            }
            setTimeout(function () {
                if (!shineFiredByAos) triggerShine();
            }, 4200);
        }
    })();
});

/* ──────────────────────────────────────────────────────────────
   FOOTER: Price reveal events
   ────────────────────────────────────────────────────────────── */
document.addEventListener('gg:price-bg-reveal', function (e) {
    var isMobile = e.detail && e.detail.isMobile;
    var wrapper  = document.querySelector(isMobile ? '.gg-price-wrapper-mobile' : '.gg-price-wrapper-desktop');
    if (wrapper) {
        wrapper.classList.add('price-revealed');
        if (isMobile && typeof window.ggRenderFooterImages === 'function') {
            setTimeout(function () { window.ggRenderFooterImages(); }, 50);
        }
    }
});

document.addEventListener('gg:price-text-reveal', function (e) {
    var isMobile  = e.detail && e.detail.isMobile;
    var priceText = document.getElementById(isMobile ? 'gg-price-text-mobile' : 'gg-price-text-desktop');
    if (priceText) {
        priceText.style.opacity = '0';
        priceText.classList.add('price-text-revealed');
    }
});

/* ──────────────────────────────────────────────────────────────
   FOOTER: Canvas image assets (force-dark fix)
   ────────────────────────────────────────────────────────────── */
(function () {
    var SRC_BG_MOBILE  = 'data:image/png;base64,';
    var SRC_PRICE_TEXT = 'data:image/png;base64,';
    var SRC_PEROKOK    = 'data:image/png;base64,';

    function drawToCanvas(canvas, img, cover) {
        if (!canvas || !img || !img.complete || img.naturalWidth === 0) return;
        var dpr = window.devicePixelRatio || 1;
        var W   = canvas.offsetWidth;
        var H   = canvas.offsetHeight;
        if (W === 0 && canvas.parentElement) W = canvas.parentElement.offsetWidth;
        if (H === 0 && canvas.parentElement) H = canvas.parentElement.offsetHeight;

        if (W === 0 || H === 0) {
            var style   = canvas.getAttribute('style') || '';
            var arMatch = style.match(/aspect-ratio\s*:\s*([\d.]+)\s*\/\s*([\d.]+)/);
            if (arMatch && W > 0)      H = Math.round(W * parseFloat(arMatch[2]) / parseFloat(arMatch[1]));
            else if (arMatch && H > 0) W = Math.round(H * parseFloat(arMatch[1]) / parseFloat(arMatch[2]));
            else                       { W = img.naturalWidth; H = img.naturalHeight; }
        }
        if (W === 0 || H === 0) return;

        canvas.width  = Math.round(W * dpr);
        canvas.height = Math.round(H * dpr);
        canvas.style.width  = W + 'px';
        canvas.style.height = H + 'px';

        var ctx = canvas.getContext('2d');
        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
        ctx.clearRect(0, 0, W, H);

        if (cover) {
            var scale = Math.max(W / img.naturalWidth, H / img.naturalHeight);
            var sw = W / scale, sh = H / scale;
            var sx = (img.naturalWidth - sw) / 2, sy = 0;
            ctx.drawImage(img, sx, sy, sw, sh, 0, 0, W, H);
        } else {
            ctx.drawImage(img, 0, 0, W, H);
        }
    }

    function renderOne(canvasId, img, cover) {
        var canvas = document.getElementById(canvasId);
        if (!canvas) return;
        drawToCanvas(canvas, img, cover);
        if (canvas.width === 0 && typeof ResizeObserver !== 'undefined') {
            var ro = new ResizeObserver(function (entries) {
                if (entries[0].contentRect.width > 0) {
                    ro.disconnect();
                    drawToCanvas(canvas, img, cover);
                }
            });
            ro.observe(canvas.parentElement || canvas);
        }
    }

    function renderFooterImages() {
        requestAnimationFrame(function () {
            renderOne('canvas-bg-price-mobile', bgMobileImg,  false);
            renderOne('gg-price-text-mobile',   priceTextImg, false);
            renderOne('canvas-perokok',         perokokImg,   true);
        });
    }

    var bgMobileImg  = new Image();
    var priceTextImg = new Image();
    var perokokImg   = new Image();
    var loadCount    = 0;

    function onLoad() {
        loadCount++;
        if (loadCount >= 3) renderFooterImages();
    }

    bgMobileImg.onload  = onLoad; bgMobileImg.src  = SRC_BG_MOBILE;
    priceTextImg.onload = onLoad; priceTextImg.src = SRC_PRICE_TEXT;
    perokokImg.onload   = onLoad; perokokImg.src   = SRC_PEROKOK;

    [bgMobileImg, priceTextImg, perokokImg].forEach(function (img) {
        if (img.complete && img.naturalWidth > 0) onLoad();
    });

    var resizeTimer;
    window.addEventListener('resize', function () {
        clearTimeout(resizeTimer);
        resizeTimer = setTimeout(renderFooterImages, 150);
    });

    window.ggRenderFooterImages = renderFooterImages;
})();

/* AOS refresh after footer loads */
document.addEventListener('DOMContentLoaded', function () {
    if (typeof AOS !== 'undefined') AOS.refresh();
});
